796 static void breakSelfRecursivePHI(const Use *U, const PHINode *PHI,
797                                   Value *&ValOut, Instruction *&CtxIOut,
798                                   const PHINode **PhiOut = nullptr) {
799   ValOut = U->get();
800   if (ValOut == PHI)
801     return;
802   CtxIOut = PHI->getIncomingBlock(*U)->getTerminator();
803   if (PhiOut)
804     *PhiOut = PHI;
805   Value *V;
806   // If the Use is a select of this phi, compute analysis on other arm to break
807   // recursion.
808   // TODO: Min/Max
809   if (match(ValOut, m_Select(m_Value(), m_Specific(PHI), m_Value(V))) ||
810       match(ValOut, m_Select(m_Value(), m_Value(V), m_Specific(PHI))))
811     ValOut = V;
812 
813   // Same for select, if this phi is 2-operand phi, compute analysis on other
814   // incoming value to break recursion.
815   // TODO: We could handle any number of incoming edges as long as we only have
816   // two unique values.
817   if (auto *IncPhi = dyn_cast<PHINode>(ValOut);
818       IncPhi && IncPhi->getNumIncomingValues() == 2) {
819     for (int Idx = 0; Idx < 2; ++Idx) {
820       if (IncPhi->getIncomingValue(Idx) == PHI) {
821         ValOut = IncPhi->getIncomingValue(1 - Idx);
822         if (PhiOut)
823           *PhiOut = IncPhi;
824         CtxIOut = IncPhi->getIncomingBlock(1 - Idx)->getTerminator();
825         break;
826       }
827     }
828   }
829 }
