831 static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
832   // Use of assumptions is context-sensitive. If we don't have a context, we
833   // cannot use them!
834   if (!Q.AC || !Q.CxtI)
835     return false;
836 
837   for (AssumptionCache::ResultElem &Elem : Q.AC->assumptionsFor(V)) {
838     if (!Elem.Assume)
839       continue;
840 
841     AssumeInst *I = cast<AssumeInst>(Elem.Assume);
842     assert(I->getFunction() == Q.CxtI->getFunction() &&
843            "Got assumption for the wrong function!");
844 
845     if (Elem.Index != AssumptionCache::ExprResultIdx) {
846       if (!V->getType()->isPointerTy())
847         continue;
848       if (RetainedKnowledge RK = getKnowledgeFromBundle(
849               *I, I->bundle_op_info_begin()[Elem.Index])) {
850         if (RK.WasOn != V)
851           continue;
852         bool AssumeImpliesNonNull = [&]() {
853           if (RK.AttrKind == Attribute::NonNull)
854             return true;
855 
856           if (RK.AttrKind == Attribute::Dereferenceable) {
857             if (NullPointerIsDefined(Q.CxtI->getFunction(),
858                                      V->getType()->getPointerAddressSpace()))
859               return false;
860             assert(RK.IRArgValue &&
861                    "Dereferenceable attribute without IR argument?");
862 
863             auto *CI = dyn_cast<ConstantInt>(RK.IRArgValue);
864             return CI && !CI->isZero();
865           }
866 
867           return false;
868         }();
869         if (AssumeImpliesNonNull && isValidAssumeForContext(I, Q.CxtI, Q.DT))
870           return true;
871       }
872       continue;
873     }
874 
875     // Warning: This loop can end up being somewhat performance sensitive.
876     // We're running this loop for once for each value queried resulting in a
877     // runtime of ~O(#assumes * #values).
878 
879     Value *RHS;
880     CmpPredicate Pred;
881     auto m_V = m_CombineOr(m_Specific(V), m_PtrToInt(m_Specific(V)));
882     if (!match(I->getArgOperand(0), m_c_ICmp(Pred, m_V, m_Value(RHS))))
883       continue;
884 
885     if (cmpExcludesZero(Pred, RHS) && isValidAssumeForContext(I, Q.CxtI, Q.DT))
886       return true;
887   }
888 
889   return false;
890 }
