342   auto &DL = Lp->getHeader()->getDataLayout();
343   Type *IdxTy = DL.getIndexType(PtrExpr->getType());
344   const SCEV *EltSizeSCEV = SE->getStoreSizeOfExpr(IdxTy, AccessTy);
345   if (SE->isLoopInvariant(PtrExpr, Lp)) {
346     ScStart = ScEnd = PtrExpr;
347   } else if (auto *AR = dyn_cast<SCEVAddRecExpr>(PtrExpr)) {
348     ScStart = AR->getStart();
349     if (!isa<SCEVCouldNotCompute>(BTC))
350       // Evaluating AR at an exact BTC is safe: LAA separately checks that
351       // accesses cannot wrap in the loop. If evaluating AR at BTC wraps, then
352       // the loop either triggers UB when executing a memory access with a
353       // poison pointer or the wrapping/poisoned pointer is not used.
354       ScEnd = AR->evaluateAtIteration(BTC, *SE);
355     else {
356       // Evaluating AR at MaxBTC may wrap and create an expression that is less
357       // than the start of the AddRec due to wrapping (for example consider
358       // MaxBTC = -2). If that's the case, set ScEnd to -(EltSize + 1). ScEnd
359       // will get incremented by EltSize before returning, so this effectively
360       // sets ScEnd to the maximum unsigned value for the type. Note that LAA
361       // separately checks that accesses cannot not wrap, so unsigned max
362       // represents an upper bound.
363       if (evaluatePtrAddRecAtMaxBTCWillNotWrap(AR, MaxBTC, EltSizeSCEV, *SE, DL,
364                                                DT, AC, LoopGuards)) {
365         ScEnd = AR->evaluateAtIteration(MaxBTC, *SE);
366       } else {
367         ScEnd = SE->getAddExpr(
368             SE->getNegativeSCEV(EltSizeSCEV),
369             SE->getSCEV(ConstantExpr::getIntToPtr(
370                 ConstantInt::getAllOnesValue(EltSizeSCEV->getType()),
371                 AR->getType())));
372       }
373     }
374     const SCEV *Step = AR->getStepRecurrence(*SE);
375 
376     // For expressions with negative step, the upper bound is ScStart and the
377     // lower bound is ScEnd.
378     if (const auto *CStep = dyn_cast<SCEVConstant>(Step)) {
379       if (CStep->getValue()->isNegative())
380         std::swap(ScStart, ScEnd);
381     } else {
382       // Fallback case: the step is not constant, but we can still
383       // get the upper and lower bounds of the interval by using min/max
384       // expressions.
385       ScStart = SE->getUMinExpr(ScStart, ScEnd);
386       ScEnd = SE->getUMaxExpr(AR->getStart(), ScEnd);
387     }
388   } else
389     return {SE->getCouldNotCompute(), SE->getCouldNotCompute()};
390 
391   assert(SE->isLoopInvariant(ScStart, Lp) && "ScStart needs to be invariant");
392   assert(SE->isLoopInvariant(ScEnd, Lp) && "ScEnd needs to be invariant");
393 
394   // Add the size of the pointed element to ScEnd.
395   ScEnd = SE->getAddExpr(ScEnd, EltSizeSCEV);
396 
397   std::pair<const SCEV *, const SCEV *> Res = {ScStart, ScEnd};
398   if (PointerBounds)
399     *PtrBoundsPair = Res;
400   return Res;
401 }
