422 bool RuntimePointerChecking::tryToCreateDiffCheck(
423     const RuntimeCheckingPtrGroup &CGI, const RuntimeCheckingPtrGroup &CGJ) {
424   // If either group contains multiple different pointers, bail out.
425   // TODO: Support multiple pointers by using the minimum or maximum pointer,
426   // depending on src & sink.
427   if (CGI.Members.size() != 1 || CGJ.Members.size() != 1)
428     return false;
429 
430   const PointerInfo *Src = &Pointers[CGI.Members[0]];
431   const PointerInfo *Sink = &Pointers[CGJ.Members[0]];
432 
433   // If either pointer is read and written, multiple checks may be needed. Bail
434   // out.
435   if (!DC.getOrderForAccess(Src->PointerValue, !Src->IsWritePtr).empty() ||
436       !DC.getOrderForAccess(Sink->PointerValue, !Sink->IsWritePtr).empty())
437     return false;
438 
439   ArrayRef<unsigned> AccSrc =
440       DC.getOrderForAccess(Src->PointerValue, Src->IsWritePtr);
441   ArrayRef<unsigned> AccSink =
442       DC.getOrderForAccess(Sink->PointerValue, Sink->IsWritePtr);
443   // If either pointer is accessed multiple times, there may not be a clear
444   // src/sink relation. Bail out for now.
445   if (AccSrc.size() != 1 || AccSink.size() != 1)
446     return false;
447 
448   // If the sink is accessed before src, swap src/sink.
449   if (AccSink[0] < AccSrc[0])
450     std::swap(Src, Sink);
451 
452   const SCEVConstant *Step;
453   const SCEV *SrcStart;
454   const SCEV *SinkStart;
455   const Loop *InnerLoop = DC.getInnermostLoop();
456   if (!match(Src->Expr,
457              m_scev_AffineAddRec(m_SCEV(SrcStart), m_SCEVConstant(Step),
458                                  m_SpecificLoop(InnerLoop))) ||
459       !match(Sink->Expr,
460              m_scev_AffineAddRec(m_SCEV(SinkStart), m_scev_Specific(Step),
461                                  m_SpecificLoop(InnerLoop))))
462     return false;
463 
464   SmallVector<Instruction *, 4> SrcInsts =
465       DC.getInstructionsForAccess(Src->PointerValue, Src->IsWritePtr);
466   SmallVector<Instruction *, 4> SinkInsts =
467       DC.getInstructionsForAccess(Sink->PointerValue, Sink->IsWritePtr);
468   Type *SrcTy = getLoadStoreType(SrcInsts[0]);
469   Type *DstTy = getLoadStoreType(SinkInsts[0]);
470   if (isa<ScalableVectorType>(SrcTy) || isa<ScalableVectorType>(DstTy))
471     return false;
472 
473   const DataLayout &DL = InnerLoop->getHeader()->getDataLayout();
474   unsigned AllocSize =
475       std::max(DL.getTypeAllocSize(SrcTy), DL.getTypeAllocSize(DstTy));
476 
477   // Only matching constant steps matching the AllocSize are supported at the
478   // moment. This simplifies the difference computation. Can be extended in the
479   // future.
