1912 static bool InstrBreaksNoSync(Instruction &I, const SCCNodeSet &SCCNodes) {
1913   // Volatile may synchronize
1914   if (I.isVolatile())
1915     return true;
1916 
1917   // An ordered atomic may synchronize.  (See comment about on monotonic.)
1918   if (llvm::isOrderedAtomic(&I))
1919     return true;
1920 
1921   auto *CB = dyn_cast<CallBase>(&I);
1922   if (!CB)
1923     // Non call site cases covered by the two checks above
1924     return false;
1925 
1926   if (CB->hasFnAttr(Attribute::NoSync))
1927     return false;
1928 
1929   // Non volatile memset/memcpy/memmoves are nosync
1930   // NOTE: Only intrinsics with volatile flags should be handled here.  All
1931   // others should be marked in Intrinsics.td.
1932   if (auto *MI = dyn_cast<MemIntrinsic>(&I))
1933     if (!MI->isVolatile())
1934       return false;
1935 
1936   // Speculatively assume in SCC.
1937   if (Function *Callee = CB->getCalledFunction())
1938     if (SCCNodes.contains(Callee))
1939       return false;
1940 
1941   return true;
