1944 /// Attempt to remove convergent function attribute when possible.
1945 ///
1946 /// Returns true if any changes to function attributes were made.
1947 static void inferConvergent(const SCCNodeSet &SCCNodes,
1948                             SmallPtrSet<Function *, 8> &Changed) {
1949   AttributeInferer AI;
1950 
1951   // Request to remove the convergent attribute from all functions in the SCC
1952   // if every callsite within the SCC is not convergent (except for calls
1953   // to functions within the SCC).
1954   // Note: Removal of the attr from the callsites will happen in
1955   // InstCombineCalls separately.
1956   AI.registerAttrInference(AttributeInferer::InferenceDescriptor{
1957       Attribute::Convergent,
1958       // Skip non-convergent functions.
1959       [](const Function &F) { return !F.isConvergent(); },
1960       // Instructions that break non-convergent assumption.
1961       [SCCNodes](Instruction &I) {
1962         return InstrBreaksNonConvergent(I, SCCNodes);
1963       },
1964       [](Function &F) {
1965         LLVM_DEBUG(dbgs() << "Removing convergent attr from fn " << F.getName()
1966                           << "\n");
1967         F.setNotConvergent();
1968       },
1969       /* RequiresExactDefinition= */ false});
1970   // Perform all the requested attribute inference actions.
1971   AI.run(SCCNodes, Changed);
1972 }
