1991         [](const Function &F) { return F.doesNotThrow(); },
1992         // Instructions that break non-throwing assumption.
1993         [&SCCNodes](Instruction &I) {
1994           return InstrBreaksNonThrowing(I, SCCNodes);
1995         },
