2009     // how functions are optimized. Thus it can be inferred only from exact
2010     // definitions.
2011     AI.registerAttrInference(AttributeInferer::InferenceDescriptor{
2012         Attribute::NoFree,
2013         // Skip functions known not to free memory.
2014         [](const Function &F) { return F.doesNotFreeMemory(); },
