2047 // Determines if the function 'F' can be marked 'norecurse'.
2048 // It returns true if any call within 'F' could lead to a recursive
2049 // call back to 'F', and false otherwise.
2050 // The 'AnyFunctionsAddressIsTaken' parameter is a module-wide flag
2051 // that is true if any function's address is taken, or if any function
2052 // has external linkage. This is used to determine the safety of
2053 // external/library calls.
2054 static bool mayHaveRecursiveCallee(Function &F,
2055                                    bool AnyFunctionsAddressIsTaken = true) {
2056   for (const auto &BB : F) {
2057     for (const auto &I : BB.instructionsWithoutDebug()) {
2058       if (const auto *CB = dyn_cast<CallBase>(&I)) {
2059         const Function *Callee = CB->getCalledFunction();
2060         if (!Callee || Callee == &F)
2061           return true;
2062 
2063         if (Callee->doesNotRecurse())
2064           continue;
2065 
2066         if (!AnyFunctionsAddressIsTaken ||
2067             (Callee->isDeclaration() &&
2068              Callee->hasFnAttribute(Attribute::NoCallback)))
2069           continue;
2070         return true;
2071       }
2072     }
2073   }
2074   return false;
2075 }
