2077 static void addNoRecurseAttrs(const SCCNodeSet &SCCNodes,
2078                               SmallPtrSet<Function *, 8> &Changed) {
2079   // Try and identify functions that do not recurse.
2080 
2081   // If the SCC contains multiple nodes we know for sure there is recursion.
2082   if (SCCNodes.size() != 1)
2083     return;
2084 
2085   Function *F = *SCCNodes.begin();
2086   if (!F || !F->hasExactDefinition() || F->doesNotRecurse())
2087     return;
2088   if (!mayHaveRecursiveCallee(*F)) {
2089     // Every call was to a non-recursive function other than this function, and
2090     // we have no indirect recursion as the SCC size is one. This function
2091     // cannot recurse.
2092     F->setDoesNotRecurse();
2093     ++NumNoRecurse;
