705 bool llvm::willNotFreeBetween(const Instruction *Assume,
706                               const Instruction *CtxI) {
707   // Helper to make sure the current function cannot arrange for
708   // another thread to free on its behalf and to check if there
709   // are any calls in the range that may free memory.
710   auto hasNoSyncOrFreeCall = [](auto Range) {
711     for (const auto &[Idx, I] : enumerate(Range)) {
712       if (Idx > MaxInstrsToCheckForFree)
713         return false;
714       if (I.isVolatile()) {
715         return false;
716       }
717 
718       // An ordered atomic may synchronize.
719       if (llvm::isOrderedAtomic(&I))
720         return false;
721 
722       auto *CB = dyn_cast<CallBase>(&I);
723       if (CB) {
724         // Non call site cases covered by the two checks above
725         if (!CB->hasFnAttr(Attribute::NoSync) ||
726             !CB->hasFnAttr(Attribute::NoFree))
727           return false;
728       }
729 
730       // Non volatile memset/memcpy/memmoves are nosync
731       if (auto *MI = dyn_cast<MemIntrinsic>(&I))
732         if (MI->isVolatile())
733           return false;
734     }
735     return true;
736   };
737 
738   // Handle cross-block case: CtxI in a successor of Assume's block.
739   const BasicBlock *CtxBB = CtxI->getParent();
740   const BasicBlock *AssumeBB = Assume->getParent();
741   BasicBlock::const_iterator CtxIter = CtxI->getIterator();
742   if (CtxBB != AssumeBB) {
743     if (CtxBB->getSinglePredecessor() != AssumeBB)
744       return false;
745 
746     if (!hasNoSyncOrFreeCall(make_range(CtxBB->begin(), CtxIter)))
747       return false;
748 
749     CtxIter = AssumeBB->end();
750   } else {
751     // Same block case: check that Assume comes before CtxI.
752     if (!Assume->comesBefore(CtxI))
753       return false;
754   }
755   // Check if there are any calls between Assume and CtxIter that may free
756   // memory.
757   return hasNoSyncOrFreeCall(make_range(Assume->getIterator(), CtxIter));
758 }
