760 // TODO: cmpExcludesZero misses many cases where `RHS` is non-constant but
761 // we still have enough information about `RHS` to conclude non-zero. For
762 // example Pred=EQ, RHS=isKnownNonZero. cmpExcludesZero is called in loops
763 // so the extra compile time may not be worth it, but possibly a second API
764 // should be created for use outside of loops.
765 static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
766   // v u> y implies v != 0.
767   if (Pred == ICmpInst::ICMP_UGT)
768     return true;
769 
770   // Special-case v != 0 to also handle v != null.
771   if (Pred == ICmpInst::ICMP_NE)
772     return match(RHS, m_Zero());
773 
774   // All other predicates - rely on generic ConstantRange handling.
775   const APInt *C;
776   auto Zero = APInt::getZero(RHS->getType()->getScalarSizeInBits());
777   if (match(RHS, m_APInt(C))) {
778     ConstantRange TrueValues = ConstantRange::makeExactICmpRegion(Pred, *C);
779     return !TrueValues.contains(Zero);
780   }
781 
782   auto *VC = dyn_cast<ConstantDataVector>(RHS);
783   if (VC == nullptr)
784     return false;
785 
786   for (unsigned ElemIdx = 0, NElem = VC->getNumElements(); ElemIdx < NElem;
787        ++ElemIdx) {
788     ConstantRange TrueValues = ConstantRange::makeExactICmpRegion(
789         Pred, VC->getElementAsAPInt(ElemIdx));
790     if (TrueValues.contains(Zero))
791       return false;
792   }
793   return true;
794 }
